mapper.select:
/* TM_CL23001_Dao_retrieveCerExcclcList */ SELECT cer_delng_de, ecs_elcpwstn_div_cd, ( SELECT cmmn_cd_nm FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_9002' AND cmmn_cd = ecs_elcpwstn_div_cd ) AS elcpwstn_nm, cer_delng_div_nm, item_nm, cer_delng_upc, cer_delng_qy, cer_amt, mrkt_div_nm, rm_ctnt, frst_regist_dt, frst_rgstr_id, last_updt_dt, last_updusr_id, updt_rsn FROM tm_cl23001 WHERE cer_delng_de LIKE SUBSTR(#{strtDt}, 0, 4) || '%'
AND ecs_elcpwstn_div_cd = #{ecsElcpwstnDivCd}
ORDER BY cer_delng_de, ecs_elcpwstn_div_cd, cer_delng_div_nm, item_nm, cer_delng_upc, cer_delng_qy

mapper.delete:
/* TM_CL23001_Dao_deleteCerExcclcList */
DELETE FROM
	tm_cl23001
WHERE
	cer_delng_de = #{cerDelngDe}
	AND ecs_elcpwstn_div_cd = #{ecsElcpwstnDivCd}
	AND cer_delng_div_nm = #{cerDelngDivNm}
	AND item_nm = #{itemNm}
	AND cer_delng_upc = #{cerDelngUpc}
	AND cer_delng_qy = #{cerDelngQy}
